-- Baseline schema migrated from the pre-versioned release.

CREATE EXTENSION IF NOT EXISTS pgcrypto;
DO $$ BEGIN CREATE TYPE role_name AS ENUM ('admin','operator','analyst','viewer'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE subject_type AS ENUM ('managed_target','one_time_audit'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE connection_mode AS ENUM ('ssh_push','pull_checkin','both','temporary_runner'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE scan_job_status AS ENUM ('queued','leased','running','completed','failed','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE scan_run_status AS ENUM ('pending','leased','running','completed','failed','stale','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
ALTER TYPE scan_job_status ADD VALUE IF NOT EXISTS 'cancelled';
ALTER TYPE scan_run_status ADD VALUE IF NOT EXISTS 'cancelled';
DO $$ BEGIN CREATE TYPE artifact_type AS ENUM ('json','markdown','sarif','pdf','scanner.raw_output','scanner.normalized_findings','scanner.enrichment_summary'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN ALTER TYPE artifact_type ADD VALUE IF NOT EXISTS 'scanner.raw_output'; END $$;
DO $$ BEGIN ALTER TYPE artifact_type ADD VALUE IF NOT EXISTS 'scanner.normalized_findings'; END $$;
DO $$ BEGIN ALTER TYPE artifact_type ADD VALUE IF NOT EXISTS 'scanner.enrichment_summary'; END $$;
DO $$ BEGIN CREATE TYPE artifact_parse_status AS ENUM ('uploaded','processing','ready','failed','quarantined'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS tenants (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slug text UNIQUE NOT NULL, name text NOT NULL, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS roles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name role_name UNIQUE NOT NULL, description text NOT NULL, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), email text UNIQUE NOT NULL, display_name text NOT NULL, password_hash text NOT NULL, disabled_at timestamptz, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS user_roles (user_id uuid REFERENCES users(id) ON DELETE CASCADE, role_id uuid REFERENCES roles(id) ON DELETE CASCADE, PRIMARY KEY(user_id, role_id));
CREATE TABLE IF NOT EXISTS role_feature_permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), role_id uuid NOT NULL REFERENCES roles(id), feature_area text NOT NULL, can_read boolean DEFAULT false, can_add boolean DEFAULT false, can_edit boolean DEFAULT false, can_delete boolean DEFAULT false, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(tenant_id, role_id, feature_area));
CREATE TABLE IF NOT EXISTS settings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid UNIQUE NOT NULL REFERENCES tenants(id), app_version text DEFAULT '0.1.0', default_artifact_retention_days integer DEFAULT 90 CHECK(default_artifact_retention_days IN (90,120,360)), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS retention_policies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, retention_days integer NOT NULL CHECK(retention_days IN (90,120,360)), is_default boolean DEFAULT false, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS environments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, slug text NOT NULL, description text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(tenant_id, slug));
CREATE TABLE IF NOT EXISTS credentials (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), label text NOT NULL, credential_type text NOT NULL, sealed_secret text NOT NULL, fingerprint text, disabled_at timestamptz, last_used_at timestamptz, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS one_time_audits (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), display_name text NOT NULL, hostname text, ip_address inet, requested_by uuid REFERENCES users(id), status text DEFAULT 'draft', connection_mode connection_mode DEFAULT 'ssh_push' CHECK(connection_mode IN ('ssh_push','temporary_runner')), retention_policy_id uuid REFERENCES retention_policies(id), promoted_target_id uuid, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS targets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), asset_mode text DEFAULT 'managed_machine', hostname text NOT NULL, fqdn text, ip_address inet, environment_id uuid REFERENCES environments(id), owner_team text, platform text, status text DEFAULT 'unknown', connection_mode connection_mode DEFAULT 'ssh_push' CHECK(connection_mode IN ('ssh_push','pull_checkin','both')), ssh_auth_method text CHECK(ssh_auth_method IS NULL OR ssh_auth_method IN ('password','ssh_key')), ssh_port integer DEFAULT 22, ssh_username text, ssh_credential_id uuid REFERENCES credentials(id), monitoring_enabled boolean DEFAULT true, schedule_enabled boolean DEFAULT false, last_seen_at timestamptz, last_status_check_at timestamptz, last_successful_scan_at timestamptz, promoted_from_audit_id uuid REFERENCES one_time_audits(id), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
DO $$ BEGIN ALTER TABLE targets ADD COLUMN IF NOT EXISTS ssh_auth_method text; EXCEPTION WHEN duplicate_column THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE targets ADD COLUMN IF NOT EXISTS ssh_port integer; EXCEPTION WHEN duplicate_column THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE targets ADD COLUMN IF NOT EXISTS ssh_username text; EXCEPTION WHEN duplicate_column THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE targets ADD COLUMN IF NOT EXISTS ssh_credential_id uuid REFERENCES credentials(id); EXCEPTION WHEN duplicate_column THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE targets ADD CONSTRAINT targets_ssh_auth_method_check CHECK (ssh_auth_method IS NULL OR ssh_auth_method IN ('password','ssh_key')); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
CREATE TABLE IF NOT EXISTS target_status_checks (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), target_id uuid NOT NULL REFERENCES targets(id), status text NOT NULL, source text NOT NULL, checked_at timestamptz DEFAULT now(), details jsonb DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS schedules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), target_id uuid NOT NULL REFERENCES targets(id), schedule_type text NOT NULL CHECK(schedule_type IN ('scan','report')), cron_expression text NOT NULL, timezone text DEFAULT 'Asia/Manila', enabled boolean DEFAULT true, next_run_at timestamptz, last_run_at timestamptz, created_by uuid REFERENCES users(id), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS target_groups (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, slug text NOT NULL, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(tenant_id, slug));
CREATE TABLE IF NOT EXISTS target_group_members (target_group_id uuid REFERENCES target_groups(id) ON DELETE CASCADE, target_id uuid REFERENCES targets(id) ON DELETE CASCADE, PRIMARY KEY(target_group_id, target_id));
CREATE TABLE IF NOT EXISTS target_identities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), target_id uuid NOT NULL REFERENCES targets(id), device_id text NOT NULL, device_cert_fingerprint text, token_hash text, enrollment_status text DEFAULT 'active', last_seen_at timestamptz, revoked_at timestamptz, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(tenant_id, device_id));
CREATE TABLE IF NOT EXISTS ssh_host_key_pins (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), target_id uuid NOT NULL REFERENCES targets(id) ON DELETE CASCADE, ssh_port integer NOT NULL CHECK(ssh_port BETWEEN 1 AND 65535), algorithm text NOT NULL CHECK(algorithm = 'ssh-ed25519'), fingerprint text NOT NULL CHECK(fingerprint LIKE 'SHA256:%'), verified_at timestamptz NOT NULL DEFAULT now(), verified_by uuid REFERENCES users(id), revoked_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id, target_id, ssh_port, fingerprint));
CREATE TABLE IF NOT EXISTS target_egress_policies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), target_id uuid NOT NULL REFERENCES targets(id) ON DELETE CASCADE, cidr cidr NOT NULL, ssh_port integer NOT NULL CHECK(ssh_port BETWEEN 1 AND 65535), enabled boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id, target_id, cidr, ssh_port));
CREATE TABLE IF NOT EXISTS target_root_policies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), target_id uuid NOT NULL REFERENCES targets(id) ON DELETE CASCADE, root_path text NOT NULL CHECK(root_path LIKE '/%' AND root_path NOT LIKE '%..%'), enabled boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id, target_id, root_path));
CREATE TABLE IF NOT EXISTS scan_jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), subject_type subject_type NOT NULL, target_id uuid REFERENCES targets(id), one_time_audit_id uuid REFERENCES one_time_audits(id), requested_by uuid REFERENCES users(id), mode connection_mode NOT NULL CHECK(mode IN ('ssh_push','pull_checkin','temporary_runner')), status scan_job_status DEFAULT 'queued', priority integer DEFAULT 50, scheduled_at timestamptz, started_at timestamptz, completed_at timestamptz, timeout_seconds integer DEFAULT 1800, scanner_version text, retry_count integer DEFAULT 0, retry_max_attempts integer NOT NULL DEFAULT 3 CHECK(retry_max_attempts BETWEEN 1 AND 10), retry_backoff_ms integer NOT NULL DEFAULT 5000 CHECK(retry_backoff_ms BETWEEN 1 AND 3600000), next_retry_at timestamptz, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), CONSTRAINT scan_jobs_exactly_one_subject CHECK (((subject_type='managed_target') AND target_id IS NOT NULL AND one_time_audit_id IS NULL) OR ((subject_type='one_time_audit') AND one_time_audit_id IS NOT NULL AND target_id IS NULL)));
ALTER TABLE scan_jobs ADD COLUMN IF NOT EXISTS retry_max_attempts integer;
ALTER TABLE scan_jobs ADD COLUMN IF NOT EXISTS retry_backoff_ms integer;
UPDATE scan_jobs SET retry_max_attempts=3 WHERE retry_max_attempts IS NULL;
UPDATE scan_jobs SET retry_backoff_ms=5000 WHERE retry_backoff_ms IS NULL;
ALTER TABLE scan_jobs ALTER COLUMN retry_max_attempts SET DEFAULT 3;
ALTER TABLE scan_jobs ALTER COLUMN retry_backoff_ms SET DEFAULT 5000;
ALTER TABLE scan_jobs ALTER COLUMN retry_max_attempts SET NOT NULL;
ALTER TABLE scan_jobs ALTER COLUMN retry_backoff_ms SET NOT NULL;
DO $$ BEGIN ALTER TABLE scan_jobs ADD CONSTRAINT scan_jobs_retry_max_attempts_check CHECK(retry_max_attempts BETWEEN 1 AND 10); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE scan_jobs ADD CONSTRAINT scan_jobs_retry_backoff_ms_check CHECK(retry_backoff_ms BETWEEN 1 AND 3600000); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
CREATE TABLE IF NOT EXISTS scan_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), job_id uuid NOT NULL REFERENCES scan_jobs(id), subject_type subject_type NOT NULL, target_id uuid REFERENCES targets(id), one_time_audit_id uuid REFERENCES one_time_audits(id), status scan_run_status DEFAULT 'pending', exit_code integer, started_at timestamptz, completed_at timestamptz, duration_seconds integer, runtime_context jsonb DEFAULT '{}'::jsonb, agent_identity text, lease_owner text, lease_expires_at timestamptz, heartbeat_at timestamptz, cancellation_requested_at timestamptz, cancellation_requested_by uuid REFERENCES users(id), cancellation_reason text, app_version text, scanner_bundle_version text, scanner_script_sha256 text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), CONSTRAINT scan_runs_exactly_one_subject CHECK (((subject_type='managed_target') AND target_id IS NOT NULL AND one_time_audit_id IS NULL) OR ((subject_type='one_time_audit') AND target_id IS NULL AND one_time_audit_id IS NOT NULL)));
ALTER TABLE scan_runs ADD COLUMN IF NOT EXISTS cancellation_requested_at timestamptz;
ALTER TABLE scan_runs ADD COLUMN IF NOT EXISTS cancellation_requested_by uuid REFERENCES users(id);
ALTER TABLE scan_runs ADD COLUMN IF NOT EXISTS cancellation_reason text;
CREATE TABLE IF NOT EXISTS worker_execution_grants (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), run_id uuid NOT NULL REFERENCES scan_runs(id) ON DELETE CASCADE, worker_id text NOT NULL, action text NOT NULL CHECK(action = 'ssh_execute'), attempt integer NOT NULL DEFAULT 1 CHECK(attempt > 0), expires_at timestamptz, consumed_at timestamptz, revoked_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT worker_execution_grants_run_attempt_key UNIQUE(tenant_id, run_id, action, attempt));
ALTER TABLE worker_execution_grants ALTER COLUMN expires_at DROP NOT NULL;
ALTER TABLE worker_execution_grants ADD COLUMN IF NOT EXISTS attempt integer;
UPDATE worker_execution_grants SET attempt=1 WHERE attempt IS NULL;
ALTER TABLE worker_execution_grants ALTER COLUMN attempt SET DEFAULT 1;
ALTER TABLE worker_execution_grants ALTER COLUMN attempt SET NOT NULL;
DO $$ BEGIN ALTER TABLE worker_execution_grants ADD CONSTRAINT worker_execution_grants_attempt_positive CHECK(attempt > 0); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN
  ALTER TABLE worker_execution_grants DROP CONSTRAINT IF EXISTS worker_execution_grants_tenant_id_run_id_action_key;
  ALTER TABLE worker_execution_grants DROP CONSTRAINT IF EXISTS worker_execution_grants_tenant_id_run_id_action_attempt_key;
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conrelid='worker_execution_grants'::regclass AND conname='worker_execution_grants_run_attempt_key') THEN
    ALTER TABLE worker_execution_grants ADD CONSTRAINT worker_execution_grants_run_attempt_key UNIQUE(tenant_id, run_id, action, attempt);
  END IF;
END $$;
CREATE TABLE IF NOT EXISTS job_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), job_id uuid REFERENCES scan_jobs(id), run_id uuid REFERENCES scan_runs(id), event_type text NOT NULL, message text NOT NULL, progress_percent integer CHECK(progress_percent IS NULL OR (progress_percent >= 0 AND progress_percent <= 100)), payload jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS job_events_worker_attempt_event_unique ON job_events (tenant_id, run_id, event_type, ((payload->>'attempt'))) WHERE event_type IN ('job.claimed','job.running','parse.started','parse.succeeded','artifact.upload_requested','artifact.upload_succeeded','job.succeeded','job.failed','job.retry_scheduled');
CREATE TABLE IF NOT EXISTS scan_dispatch_outbox (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), job_id uuid NOT NULL REFERENCES scan_jobs(id) ON DELETE CASCADE, run_id uuid NOT NULL REFERENCES scan_runs(id) ON DELETE CASCADE, queue_type text NOT NULL CHECK(queue_type = 'scan_jobs'), payload jsonb NOT NULL CHECK(jsonb_typeof(payload) = 'object' AND payload - ARRAY['id','jobId','runId','run_id','subjectType','subject_type','targetId','target_id','oneTimeAuditId','one_time_audit_id'] = '{}'::jsonb), attempt_count integer NOT NULL DEFAULT 0 CHECK(attempt_count >= 0), last_attempt_at timestamptz, next_attempt_at timestamptz, failed_at timestamptz, last_error text, published_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id, run_id, queue_type));
ALTER TABLE scan_dispatch_outbox ADD COLUMN IF NOT EXISTS next_attempt_at timestamptz;
ALTER TABLE scan_dispatch_outbox ADD COLUMN IF NOT EXISTS failed_at timestamptz;
ALTER TABLE scan_dispatch_outbox ADD COLUMN IF NOT EXISTS last_error text;
CREATE TABLE IF NOT EXISTS artifacts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), run_id uuid NOT NULL REFERENCES scan_runs(id), artifact_type artifact_type NOT NULL, storage_uri text NOT NULL, sha256 text NOT NULL CHECK(sha256 ~ '^[a-f0-9]{64}$'), mime_type text, size_bytes bigint NOT NULL CHECK(size_bytes > 0), parse_status artifact_parse_status DEFAULT 'uploaded', retention_policy_id uuid REFERENCES retention_policies(id), retention_expires_at timestamptz, created_at timestamptz DEFAULT now(), UNIQUE(run_id, artifact_type, sha256));
CREATE TABLE IF NOT EXISTS artifact_cleanup_work (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), run_id uuid NOT NULL REFERENCES scan_runs(id), artifact_id uuid REFERENCES artifacts(id) ON DELETE SET NULL, storage_uri text NOT NULL, reason text NOT NULL, status text NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','processing','failed','completed')), attempt_count integer NOT NULL DEFAULT 0 CHECK(attempt_count >= 0), last_error text, completed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id, artifact_id));
CREATE TABLE IF NOT EXISTS findings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), scanner_finding_id text NOT NULL, title text NOT NULL, category text, severity text NOT NULL CHECK(severity IN ('critical','high','medium','low','informational')), description text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(tenant_id, scanner_finding_id));
CREATE TABLE IF NOT EXISTS finding_instances (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), finding_id uuid NOT NULL REFERENCES findings(id), run_id uuid NOT NULL REFERENCES scan_runs(id), target_id uuid REFERENCES targets(id), one_time_audit_id uuid REFERENCES one_time_audits(id), status text DEFAULT 'open', evidence_summary text, source_artifact_id uuid REFERENCES artifacts(id), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS remediation_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), finding_instance_id uuid NOT NULL REFERENCES finding_instances(id), source text DEFAULT 'scanner_generated', priority text, category text, title text NOT NULL, action text, file_path text, instructions text, status text DEFAULT 'open' CHECK(status IN ('open','accepted','ignored','resolved')), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS notification_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), event_type text NOT NULL, target_id uuid REFERENCES targets(id), run_id uuid REFERENCES scan_runs(id), delivery_state text DEFAULT 'pending', payload jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS alert_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), event_type text NOT NULL, enabled boolean DEFAULT true, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS notification_email_templates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), event_type text NOT NULL, subject_template text NOT NULL, body_template text NOT NULL, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS smtp_settings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid UNIQUE NOT NULL REFERENCES tenants(id), host text, port integer, encryption_mode text, username text, sealed_password text, from_address text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS knowledgebase_categories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, slug text NOT NULL, description text, sort_order integer DEFAULT 0, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(tenant_id, slug));
CREATE TABLE IF NOT EXISTS knowledgebase_articles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), category_id uuid REFERENCES knowledgebase_categories(id), slug text NOT NULL, title text NOT NULL, summary text, body_markdown text NOT NULL, audience text DEFAULT 'all', status text DEFAULT 'published', tags text[] DEFAULT '{}', created_by uuid REFERENCES users(id), updated_by uuid REFERENCES users(id), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), published_at timestamptz, UNIQUE(tenant_id, slug));
CREATE TABLE IF NOT EXISTS audit_log (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), actor_user_id uuid REFERENCES users(id), action text NOT NULL, resource_type text NOT NULL, resource_id uuid, ip_address inet, user_agent text, payload jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS dashboard_summaries (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), summary_date date DEFAULT CURRENT_DATE, metrics jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(tenant_id, summary_date));
CREATE INDEX IF NOT EXISTS scan_jobs_subject_idx ON scan_jobs(tenant_id, subject_type, target_id, one_time_audit_id);
CREATE INDEX IF NOT EXISTS scan_runs_job_idx ON scan_runs(tenant_id, job_id, status);
CREATE INDEX IF NOT EXISTS scan_dispatch_outbox_scope_idx ON scan_dispatch_outbox(tenant_id, run_id, job_id);
CREATE INDEX IF NOT EXISTS scan_dispatch_outbox_pending_idx ON scan_dispatch_outbox(created_at) WHERE published_at IS NULL;
CREATE INDEX IF NOT EXISTS scan_dispatch_outbox_due_idx ON scan_dispatch_outbox(next_attempt_at,created_at) WHERE published_at IS NULL AND failed_at IS NULL;
CREATE INDEX IF NOT EXISTS job_events_run_created_idx ON job_events(tenant_id, run_id, created_at DESC);
CREATE INDEX IF NOT EXISTS artifacts_run_idx ON artifacts(tenant_id, run_id, artifact_type);
CREATE INDEX IF NOT EXISTS artifact_cleanup_work_pending_idx ON artifact_cleanup_work(tenant_id, run_id, status, created_at);
